class Solution:
    def minimumCost(self, source: str, target: str, original: List[str], changed: List[str], cost: List[int]) -> int:
        n = len(source)
        graph = defaultdict(list)
        for i in range(n):
            if i < n - 1 and source[i:i+2] == target[i:i+2]:
                graph[source[i]].append((target[i+1], 0))
                graph[target[i]].append((target[i+1], 0))
            if source[i] == target[i]:
                graph[source[i]].append((target[i], 0))

        for o, c, co in zip(original, changed, cost):
            graph[o].append((c, co))

        min_cost = [float('inf')] * 26
        min_cost[ord(source[0]) - ord('a')] = 0
        pq = [(0, source[0])]
        while pq:
            c, node = heapq.heappop(pq)
            if c != min_cost[ord(node) - ord('a')]:
                continue
            for nxt, nxt_cost in graph[node]:
                nxt_cost += c
                if nxt_cost < min_cost[ord(nxt) - ord('a')]:
                    min_cost[ord(nxt) - ord('a')] = nxt_cost
                    heapq.heappush(pq, (nxt_cost, nxt))

        res = 0
        for i in range(n):
            res += min_cost[ord(target[i]) - ord('a')]
        return res if res < float('inf') else -1
