class Solution:
    def earliestSecondToMarkIndices(self, nums: List[int], changeIndices: List[int]) -> int:
        n, m = len(nums), len(changeIndices)
        change_dict = {changeIndices[i]: i for i in range(m)}
        q = deque([(i, 0) for i in range(n) if nums[i] == 0])
        marked = [False] * n
        time = [-1] * n

        while q:
            i, t = q.popleft()
            if marked[i]:
                continue
            marked[i] = True
            time[i] = t
            if i in change_dict:
                q.append((changeIndices[change_dict[i]], t + 1))
            if nums[i] > 0:
                nums[i] -= 1
                q.append((i, t + 1))

        if any(not marked[i] for i in range(n)):
            return -1
        return max(time)
