import sys
from collections import defaultdict

def read_input():
    N, M = map(int, sys.stdin.readline().split())
    edges = [tuple(map(int, sys.stdin.readline().split())) for _ in range(M)]
    return N, M, edges

def solve(N, M, edges):
    graph = defaultdict(list)
    for u, v, w in edges:
        graph[u].append((v, w))

    dp = [[float('inf')] * (1 << N) for _ in range(N)]
    dp[0][1] = 0

    for s in range(1 << N):
        for v in range(N):
            if dp[v][s] != float('inf'):
                for u, w in graph[v + 1]:
                    if (s & (1 << (u - 1))) == 0:
                        ns = s | (1 << (u - 1))
                        dp[u - 1][ns] = min(dp[u - 1][ns], dp[v][s] + w)

    return min(dp[i][(1 << N) - 1] for i in range(N))

def main():
    N, M, edges = read_input()
    ans = solve(N, M, edges)
    if ans == float('inf'):
        print('No')
    else:
        print(ans)

if __name__ == '__main__':
