class Solution:
    def minimumCoins(self, prices: List[int]) -> int:
        n = len(prices)
        dp = [0] * (n + 1)
        for i in range(1, n + 1):
            dp[i] = min(dp[i - 1] + prices[i - 1], dp[i])
            if i >= 2:
                dp[i] = min(dp[i], dp[i - 2] + prices[i - 1])
        return dp[n]
